import React, { useState } from 'react';
import { patientSignup } from '../../services/patientAuth';
import './PatientSignup.css';

const PatientSignup = ({ onSwitchToLogin }) => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    // Personal Information - REQUIRED
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    phone: '',
    gender: '',

    // Medical Information
    bloodGroup: '',
    height: '',
    weight: '',
    allergies: '',
    currentMedications: '',
    emergencyContact: '',
    emergencyPhone: '',
    address: '',

    // Insurance Information (Optional)
    insuranceProvider: '',
    insuranceId: ''
  });

  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});

  const bloodGroups = ['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'];
  const genders = ['Male', 'Female', 'Other'];

  // Country codes for phone validation
  const countryCodes = {
    'IN': { code: '+91', pattern: /^[6-9]\d{9}$/, name: 'India' },
    'US': { code: '+1', pattern: /^\d{10}$/, name: 'USA' },
    'UK': { code: '+44', pattern: /^\d{10}$/, name: 'UK' },
    'AE': { code: '+971', pattern: /^[5]\d{8}$/, name: 'UAE' },
    'SA': { code: '+966', pattern: /^[5]\d{8}$/, name: 'Saudi Arabia' }
  };

  const [selectedCountry, setSelectedCountry] = useState('IN');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });

    // Clear error for this field when user types
    if (errors[name]) {
      setErrors({
        ...errors,
        [name]: null
      });
    }
  };

  const handleBlur = (field) => {
    setTouched({
      ...touched,
      [field]: true
    });
    validateField(field);
  };

  const validateField = (field) => {
    let error = '';
    const value = formData[field];

    switch(field) {
      case 'name':
        if (!value || value.trim() === '') error = 'Full name is required';
        else if (value.length < 2) error = 'Name must be at least 2 characters';
        break;

      case 'email':
        if (!value) error = 'Email is required';
        else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
          error = 'Please enter a valid email address';
        }
        break;

      case 'password':
        if (!value) error = 'Password is required';
        else if (value.length < 8) error = 'Password must be at least 8 characters';
        else if (!/[A-Z]/.test(value)) error = 'Password must contain at least one capital letter';
        else if (!/[!@#$%^&*(),.?":{}|<>]/.test(value)) {
          error = 'Password must contain at least one special character';
        }
        break;

      case 'confirmPassword':
        if (value !== formData.password) error = 'Passwords do not match';
        break;

      case 'phone':
        if (!value) error = 'Phone number is required';
        else {
          const countryPattern = countryCodes[selectedCountry].pattern;
          if (!countryPattern.test(value)) {
            error = `Please enter a valid ${countryCodes[selectedCountry].name} phone number`;
          }
        }
        break;

      case 'gender':
        if (!value) error = 'Please select your gender';
        break;

      case 'emergencyPhone':
        if (value) {
          const countryPattern = countryCodes[selectedCountry].pattern;
          if (!countryPattern.test(value)) {
            error = `Please enter a valid ${countryCodes[selectedCountry].name} emergency number`;
          }
        }
        break;

      default:
        break;
    }

    setErrors(prev => ({ ...prev, [field]: error }));
    return !error;
  };

  const validateStep1 = () => {
    const fields = ['name', 'email', 'password', 'confirmPassword', 'phone', 'gender'];
    let isValid = true;

    fields.forEach(field => {
      if (!validateField(field)) isValid = false;
    });

    return isValid;
  };

  const validateStep2 = () => {
    const fields = ['emergencyContact'];
    let isValid = true;

    fields.forEach(field => {
      if (!formData[field] || formData[field].trim() === '') {
        setErrors(prev => ({ ...prev, [field]: 'Emergency contact name is required' }));
        isValid = false;
      }
    });

    // Emergency phone is optional but if provided must be valid
    if (formData.emergencyPhone && !validateField('emergencyPhone')) {
      isValid = false;
    }

    return isValid;
  };

  const handleNext = (e) => {
    e.preventDefault();
    if (validateStep1()) {
      setStep(2);
      window.scrollTo(0, 0);
    }
  };

  const handlePrevious = (e) => {
    e.preventDefault();
    setStep(1);
    window.scrollTo(0, 0);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateStep2()) {
      return;
    }

    setLoading(true);
    setError('');

    try {
      // Format phone with country code
      const fullPhone = `${countryCodes[selectedCountry].code}${formData.phone}`;
      const fullEmergencyPhone = formData.emergencyPhone 
        ? `${countryCodes[selectedCountry].code}${formData.emergencyPhone}` 
        : '';

      const completeData = {
        ...formData,
        phone: fullPhone,
        emergencyPhone: fullEmergencyPhone,
        countryCode: selectedCountry
      };

      await patientSignup(completeData);
      onSwitchToLogin();
    } catch (error) {
      setError(error.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="patient-signup-container professional">
      <div className="signup-header">
        <h2>Create Patient Account</h2>
        <p className="time-display">{new Date().toLocaleString('en-US', { 
          weekday: 'long', 
          year: 'numeric', 
          month: 'long', 
          day: 'numeric',
          hour: '2-digit',
          minute: '2-digit'
        })}</p>
      </div>

      {error && (
        <div className="error-alert">
          <i className="fas fa-exclamation-circle"></i>
          {error}
        </div>
      )}

      {/* Professional Progress Steps */}
      <div className="progress-steps professional">
        <div className={`progress-step ${step >= 1 ? 'active' : ''} ${step > 1 ? 'completed' : ''}`}>
          <div className="step-indicator">{step > 1 ? '✓' : '1'}</div>
          <div className="step-content">
            <span className="step-label">Personal Information</span>
            <span className="step-desc">Basic details</span>
          </div>
        </div>
        <div className={`progress-line ${step >= 2 ? 'active' : ''}`}></div>
        <div className={`progress-step ${step >= 2 ? 'active' : ''}`}>
          <div className="step-indicator">2</div>
          <div className="step-content">
            <span className="step-label">Medical Information</span>
            <span className="step-desc">Health details</span>
          </div>
        </div>
      </div>

      <form onSubmit={step === 2 ? handleSubmit : handleNext} noValidate>
        {/* Step 1: Personal Information */}
        {step === 1 && (
          <div className="form-step fade-in">
            <div className="step-header">
              <i className="fas fa-user-circle"></i>
              <h3>Personal Information</h3>
            </div>

            <div className="form-grid">
              {/* Full Name - Required */}
              <div className="form-group full-width required">
                <label>Full Name <span className="required-star">*</span></label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  onBlur={() => handleBlur('name')}
                  placeholder="Enter your full name"
                  className={touched.name && errors.name ? 'error' : ''}
                />
                {touched.name && errors.name && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.name}</span>
                )}
              </div>

              {/* Email - Required with validation */}
              <div className="form-group full-width required">
                <label>Email Address <span className="required-star">*</span></label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  onBlur={() => handleBlur('email')}
                  placeholder="patient@example.com"
                  className={touched.email && errors.email ? 'error' : ''}
                />
                {touched.email && errors.email && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.email}</span>
                )}
              </div>

              {/* Password - Required with strong validation */}
              <div className="form-group half-width required">
                <label>Password <span className="required-star">*</span></label>
                <input
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  onBlur={() => handleBlur('password')}
                  placeholder="At least 8 chars, 1 capital, 1 special"
                  className={touched.password && errors.password ? 'error' : ''}
                />
                {touched.password && errors.password && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.password}</span>
                )}
                <div className="password-requirements">
                  <span className={formData.password.length >= 8 ? 'valid' : ''}>✓ 8+ chars</span>
                  <span className={/[A-Z]/.test(formData.password) ? 'valid' : ''}>✓ Capital letter</span>
                  <span className={/[!@#$%^&*(),.?":{}|<>]/.test(formData.password) ? 'valid' : ''}>✓ Special char</span>
                </div>
              </div>

              <div className="form-group half-width required">
                <label>Confirm Password <span className="required-star">*</span></label>
                <input
                  type="password"
                  name="confirmPassword"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                  onBlur={() => handleBlur('confirmPassword')}
                  placeholder="Re-enter password"
                  className={touched.confirmPassword && errors.confirmPassword ? 'error' : ''}
                />
                {touched.confirmPassword && errors.confirmPassword && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.confirmPassword}</span>
                )}
              </div>

              {/* Phone with Country Code - Required */}
              <div className="form-group phone-group required">
                <label>Phone Number <span className="required-star">*</span></label>
                <div className="phone-input-container">
                  <select 
                    value={selectedCountry}
                    onChange={(e) => setSelectedCountry(e.target.value)}
                    className="country-select"
                  >
                    {Object.entries(countryCodes).map(([key, { code, name }]) => (
                      <option key={key} value={key}>{code} {name}</option>
                    ))}
                  </select>
                  <input
                    type="tel"
                    name="phone"
                    value={formData.phone}
                    onChange={handleChange}
                    onBlur={() => handleBlur('phone')}
                    placeholder="Enter phone number"
                    className={touched.phone && errors.phone ? 'error' : ''}
                  />
                </div>
                {touched.phone && errors.phone && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.phone}</span>
                )}
              </div>

              {/* Gender - Required */}
              <div className="form-group full-width required">
                <label>Gender <span className="required-star">*</span></label>
                <div className="gender-options">
                  {genders.map(gender => (
                    <label key={gender} className="gender-option">
                      <input
                        type="radio"
                        name="gender"
                        value={gender}
                        checked={formData.gender === gender}
                        onChange={handleChange}
                        onBlur={() => handleBlur('gender')}
                      />
                      <span className="gender-label">{gender}</span>
                    </label>
                  ))}
                </div>
                {touched.gender && errors.gender && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.gender}</span>
                )}
              </div>

              {/* Removed Profile Photo section */}
            </div>

            {/* Form Actions for Step 1 */}
            <div className="form-actions">
              <button 
                type="submit" 
                className="btn btn-primary next-btn"
                disabled={!validateStep1() && Object.keys(touched).length > 0}
              >
                Next Step <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {/* Step 2: Medical Information */}
        {step === 2 && (
          <div className="form-step fade-in">
            <div className="step-header">
              <i className="fas fa-notes-medical"></i>
              <h3>Medical Information</h3>
            </div>

            <div className="form-grid">
              {/* Blood Group - Optional */}
              <div className="form-group third-width">
                <label>Blood Group</label>
                <select 
                  name="bloodGroup" 
                  value={formData.bloodGroup} 
                  onChange={handleChange}
                >
                  <option value="">Select Blood Group</option>
                  {bloodGroups.map(group => (
                    <option key={group} value={group}>{group}</option>
                  ))}
                </select>
              </div>

              <div className="form-group third-width">
                <label>Height (cm)</label>
                <input
                  type="number"
                  name="height"
                  value={formData.height}
                  onChange={handleChange}
                  placeholder="e.g., 175"
                  min="1"
                  max="300"
                />
              </div>

              <div className="form-group third-width">
                <label>Weight (kg)</label>
                <input
                  type="number"
                  name="weight"
                  value={formData.weight}
                  onChange={handleChange}
                  placeholder="e.g., 70"
                  min="1"
                  max="500"
                />
              </div>

              <div className="form-group full-width">
                <label>Known Allergies</label>
                <textarea
                  name="allergies"
                  value={formData.allergies}
                  onChange={handleChange}
                  placeholder="List any allergies (e.g., Penicillin, Peanuts)"
                  rows="2"
                />
              </div>

              <div className="form-group full-width">
                <label>Current Medications</label>
                <textarea
                  name="currentMedications"
                  value={formData.currentMedications}
                  onChange={handleChange}
                  placeholder="List current medications with dosage"
                  rows="2"
                />
              </div>

              {/* Emergency Contact - Required */}
              <div className="form-group half-width required">
                <label>Emergency Contact Name <span className="required-star">*</span></label>
                <input
                  type="text"
                  name="emergencyContact"
                  value={formData.emergencyContact}
                  onChange={handleChange}
                  onBlur={() => handleBlur('emergencyContact')}
                  placeholder="Full name"
                  className={touched.emergencyContact && errors.emergencyContact ? 'error' : ''}
                />
                {touched.emergencyContact && errors.emergencyContact && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.emergencyContact}</span>
                )}
              </div>

              {/* Emergency Phone - Optional but validated */}
              <div className="form-group half-width">
                <label>Emergency Phone (Optional)</label>
                <div className="phone-input-container">
                  <select 
                    value={selectedCountry}
                    onChange={(e) => setSelectedCountry(e.target.value)}
                    className="country-select"
                  >
                    {Object.entries(countryCodes).map(([key, { code, name }]) => (
                      <option key={key} value={key}>{code}</option>
                    ))}
                  </select>
                  <input
                    type="tel"
                    name="emergencyPhone"
                    value={formData.emergencyPhone}
                    onChange={handleChange}
                    onBlur={() => handleBlur('emergencyPhone')}
                    placeholder="Emergency number"
                    className={touched.emergencyPhone && errors.emergencyPhone ? 'error' : ''}
                  />
                </div>
                {touched.emergencyPhone && errors.emergencyPhone && (
                  <span className="error-message"><i className="fas fa-exclamation-circle"></i> {errors.emergencyPhone}</span>
                )}
              </div>

              <div className="form-group full-width">
                <label>Address</label>
                <textarea
                  name="address"
                  value={formData.address}
                  onChange={handleChange}
                  placeholder="Your full address"
                  rows="2"
                />
              </div>
            </div>

            {/* Insurance Information Section - Optional */}
            <div className="insurance-section">
              <div className="insurance-header">
                <i className="fas fa-shield-alt"></i>
                <h4>Insurance Information (Optional)</h4>
              </div>

              <div className="form-grid">
                <div className="form-group half-width">
                  <label>Insurance Provider</label>
                  <input
                    type="text"
                    name="insuranceProvider"
                    value={formData.insuranceProvider}
                    onChange={handleChange}
                    placeholder="e.g., Blue Cross"
                  />
                </div>

                <div className="form-group half-width">
                  <label>Insurance ID</label>
                  <input
                    type="text"
                    name="insuranceId"
                    value={formData.insuranceId}
                    onChange={handleChange}
                    placeholder="Policy number"
                  />
                </div>
              </div>
            </div>

            {/* Form Actions for Step 2 */}
            <div className="form-actions">
              <button type="button" className="btn btn-outline" onClick={handlePrevious}>
                <i className="fas fa-arrow-left"></i> Previous
              </button>
              <button type="submit" className="btn btn-success submit-btn" disabled={loading}>
                {loading ? (
                  <><i className="fas fa-spinner fa-spin"></i> Registering...</>
                ) : (
                  <><i className="fas fa-check-circle"></i> Complete Registration</>
                )}
              </button>
            </div>
          </div>
        )}
      </form>

      <div className="signup-footer">
        <p>Already have an account?</p>
        <button type="button" className="login-link" onClick={onSwitchToLogin}>
          Sign In <i className="fas fa-arrow-right"></i>
        </button>
      </div>
    </div>
  );
};

export default PatientSignup;
